DEPLOY_SCRIPT = """
#!/usr/bin/env bash
# deploy.sh - Deploy the Cloud Function with a LEAST-PRIVILEGE service account
#
# SECURITY BEST PRACTICE: Instead of granting broad roles like
#   - roles/storage.admin
#   - roles/datastore.user (project-wide)
#   - roles/pubsub.publisher (project-wide)
#
# We create a dedicated service account and grant only the minimum
# permissions needed, scoped to specific resources where possible.

set -euo pipefail

PROJECT_ID="${GCP_PROJECT_ID:?Set GCP_PROJECT_ID}"
REGION="${GCP_REGION:-us-central1}"
FUNCTION_NAME="file-processor"
SA_NAME="file-processor-sa"
SA_EMAIL="${SA_NAME}@${PROJECT_ID}.iam.gserviceaccount.com"
TRIGGER_BUCKET="${TRIGGER_BUCKET:?Set TRIGGER_BUCKET}"
PUBSUB_TOPIC="${PUBSUB_TOPIC:-file-processing-events}"

echo "==> Creating dedicated service account..."
gcloud iam service-accounts create "${SA_NAME}" \\
    --display-name="File Processor Function SA" \\
    --project="${PROJECT_ID}" 2>/dev/null || true

# -----------------------------------------------------------------------
# LEAST-PRIVILEGE PERMISSIONS (recommended for production)
# -----------------------------------------------------------------------

# 1. Storage: Grant objectViewer ONLY on the specific bucket (not admin!)
#    If the function also needs to write/delete, use objectAdmin on that
#    single bucket instead of project-wide storage.admin.
echo "==> Granting Storage Object Viewer on trigger bucket..."
gsutil iam ch "serviceAccount:${SA_EMAIL}:roles/storage.objectViewer" \\
    "gs://${TRIGGER_BUCKET}"

# 2. Firestore/Datastore: Grant datastore.user at project level
#    (Firestore doesn't support resource-level IAM, but you can use
#    Firestore Security Rules for additional document-level control)
echo "==> Granting Datastore User..."
gcloud projects add-iam-policy-binding "${PROJECT_ID}" \\
    --member="serviceAccount:${SA_EMAIL}" \\
    --role="roles/datastore.user" \\
    --condition=None

# 3. Pub/Sub: Grant publisher ONLY on the specific topic
echo "==> Granting Pub/Sub Publisher on specific topic..."
gcloud pubsub topics add-iam-policy-binding "${PUBSUB_TOPIC}" \\
    --member="serviceAccount:${SA_EMAIL}" \\
    --role="roles/pubsub.publisher" \\
    --project="${PROJECT_ID}"

# -----------------------------------------------------------------------
# Deploy the function
# -----------------------------------------------------------------------
echo "==> Creating Pub/Sub topic (if not exists)..."
gcloud pubsub topics create "${PUBSUB_TOPIC}" --project="${PROJECT_ID}" 2>/dev/null || true

echo "==> Deploying Cloud Function (Gen2)..."
gcloud functions deploy "${FUNCTION_NAME}" \\
    --gen2 \\
    --region="${REGION}" \\
    --runtime=python311 \\
    --source=. \\
    --entry-point=process_gcs_event \\
    --trigger-event-filters="type=google.cloud.storage.object.v1.finalized" \\
    --trigger-event-filters="bucket=${TRIGGER_BUCKET}" \\
    --service-account="${SA_EMAIL}" \\
    --set-env-vars="GCP_PROJECT_ID=${PROJECT_ID},PUBSUB_TOPIC=${PUBSUB_TOPIC},FIRESTORE_COLLECTION=processed_files" \\
    --memory=256MB \\
    --timeout=120s \\
    --max-instances=10 \\
    --project="${PROJECT_ID}"

echo "==> Deployment complete."
echo ""
echo "SECURITY NOTES:"
echo "  - Service account: ${SA_EMAIL}"
echo "  - Storage access: objectViewer on gs://${TRIGGER_BUCKET} only"
echo "  - Firestore access: datastore.user (project-level, use Security Rules for finer control)"
echo "  - Pub/Sub access: publisher on topic '${PUBSUB_TOPIC}' only"
echo ""
echo "  DO NOT use roles/storage.admin, roles/pubsub.admin, or roles/owner"
echo "  for Cloud Function service accounts in production."
"""

